#include <iostream>

using namespace std;

int main() {
    int D, H, M;
    cin >> D >> H >> M;

    // Reference time: November 11, 11:11
    // Total minutes from start of day 11, 00:00 to the reference point
    int ref_total = 11 * 24 * 60 + 11 * 60 + 11;

    // Total minutes from start of day 11, 00:00 to the given finish time
    int finish_total = D * 24 * 60 + H * 60 + M;

    int diff = finish_total - ref_total;
    cout << diff << endl;

    return 0;
}
